#include<bits/stdc++.h>
using namespace std;
int n;
int a[35][35];
int dx[]= {-1,1,0,0};
int dy[]= {0,0,-1,1};
void dfs(int x,int y) {
	if(a[x][y]==1) {
		return;
	}
	a[x][y]=-1;
	for(int i=0; i<4; i++) {
		int nx=x+dx[i];
		int ny=y+dy[i];
		if(nx>=1&&nx<=n&&ny>=1&&ny<=n&&a[nx][ny]==0) {
			dfs(nx,ny);
		}
	}
}
int main() {
	cin>>n;
	for(int i=1; i<=n; i++) {
		for(int j=1; j<=n; j++) {
			cin>>a[i][j];
		}
	}
	for(int i=1; i<=n; i++) {
		if(a[i][1]==0) {
			dfs(i,1);
		}
		if(a[i][n]==0) {
			dfs(i,n);
		}
		if(a[1][i]==0) {
			dfs(1,i);
		}
		if(a[n][i]==0) {
			dfs(n,i);
		}
	}
	for(int i=1; i<=n; i++) {
		for(int j=1; j<=n; j++) {
			if(a[i][j]==0) {
				a[i][j]=2;
			}
		}
	}
	for(int i=1; i<=n; i++) {
		for(int j=1; j<=n; j++) {
			if(a[i][j]==-1) {
				a[i][j]=0;
			}
		}
	}
	for(int i=1; i<=n; i++) {
		for(int j=1; j<=n; j++)cout<<a[i][j]<<" ";
		cout<<endl;
	}
	return 0;
}
